const item = $input.first().json || {};
const body = item.body || item;
const expectedPassword = 'gundam';
const password = String(body.password || '').trim();
const range = String(body.range || '30').trim();

const days = Number(range);
let cutoffISO = '2000-01-01T00:00:00.000Z';
if (Number.isFinite(days)) {
  cutoffISO = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
}

return [{
  json: {
    ok: password && password === expectedPassword,
    range,
    cutoffISO,
    response: { ok: false, message: '管理密碼錯誤或沒有權限' }
  }
}];

const auth = $('驗證管理密碼').first().json || {};
const range = auth.range || '30';
const batches = $('讀取掃描批次').all().map((item) => item.json || {});
const details = $input.all().map((item) => item.json || {});

function propVal(row, name) {
  const p = row?.properties?.[name];
  if (p) {
    switch (p.type) {
      case 'title': return (p.title || []).map((t) => t.plain_text).join('');
      case 'rich_text': return (p.rich_text || []).map((t) => t.plain_text).join('');
      case 'select': return p.select?.name || '';
      case 'status': return p.status?.name || '';
      case 'multi_select': return (p.multi_select || []).map((o) => o.name);
      case 'number': return p.number ?? '';
      case 'checkbox': return p.checkbox === true;
      case 'date': return p.date?.start || '';
      case 'url': return p.url || '';
      case 'formula': return p.formula ? (p.formula[p.formula.type] ?? '') : '';
      default: return '';
    }
  }
  if (row?.[name] !== undefined && row?.[name] !== null) return row[name];
  if (row?.['property_' + name] !== undefined && row?.['property_' + name] !== null) return row['property_' + name];
  return '';
}

function batchTime(row) {
  return propVal(row, '上傳時間') || row.created_time || row.createdTime || propVal(row, '完成時間') || '';
}
function detailTime(row) {
  return row.created_time || row.createdTime || propVal(row, '日期') || '';
}

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}

function truthy(value) {
  return value === true || value === '__YES__' || value === 'true' || value === 1;
}

function parseTime(value) {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const time = new Date(raw);
  return Number.isNaN(time.getTime()) ? null : time;
}

function dayKey(time) {
  if (!time) return '';
  const y = time.getFullYear();
  const m = String(time.getMonth() + 1).padStart(2, '0');
  const d = String(time.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

function inRange(timeStr) {
  if (range === 'all') return true;
  const days = Number(range || 30);
  if (!Number.isFinite(days)) return true;
  const time = parseTime(timeStr);
  if (!time) return true;
  const cutoff = new Date(Date.now() - days * 24 * 60 * 60 * 1000);
  return time >= cutoff;
}

function sameDay(date) {
  if (!date) return false;
  const now = new Date();
  return date.getFullYear() === now.getFullYear() && date.getMonth() === now.getMonth() && date.getDate() === now.getDate();
}

function errorTypesOf(row) {
  const raw = propVal(row, '錯誤類型');
  let types = [];
  if (Array.isArray(raw)) types = raw.map((x) => String(x?.name || x).trim()).filter(Boolean);
  else if (typeof raw === 'string' && raw.trim()) types = raw.split(/[,，、]/).map((s) => s.trim()).filter(Boolean);
  if (types.length) return types;
  const reason = String(propVal(row, '異常原因') || propVal(row, '備註') || '');
  const known = ['製令單號未判讀', '品號未判讀', '品號開頭非英文', '主檔查無品號', '規格未判讀', '規格不符', '字跡模糊'];
  return known.filter((k) => reason.includes(k));
}

const people = (() => { try { return $('讀取人員清單').all().map((i) => i.json || {}); } catch (e) { return []; } })();
const nickById = new Map();
const nickByName = new Map();
for (const p of people) {
  const uid = String(propVal(p, 'LINE userId')).trim();
  const nm = String(propVal(p, '名稱')).trim();
  const nk = String(propVal(p, '暱稱')).trim();
  if (!nk) continue;
  if (uid) nickById.set(uid, nk);
  if (nm) nickByName.set(nm, nk);
}
function nickOf(userId, name) {
  return nickById.get(String(userId || '').trim()) || nickByName.get(String(name || '').trim()) || '';
}

const scopedDetails = details.filter((row) => inRange(detailTime(row)));
const scopedBatches = batches.filter((row) => inRange(batchTime(row)));
const passedDetails = scopedDetails.filter((row) => propVal(row, '比對結果') === 'OK');
const abnormalDetails = scopedDetails.filter((row) => propVal(row, '比對結果') === '異常');

const operatorMap = new Map();
for (const row of scopedDetails) {
  const userId = String(propVal(row, 'LINE userId')).trim();
  const name = String(propVal(row, '操作人') || userId || '未命名').trim();
  const key = userId || name;
  if (!operatorMap.has(key)) operatorMap.set(key, { name, userId, total: 0, passed: 0, abnormal: 0, corrected: 0 });
  const item = operatorMap.get(key);
  item.total += 1;
  const status = propVal(row, '比對結果');
  if (status === 'OK') item.passed += 1;
  if (status === '異常') item.abnormal += 1;
  if (truthy(propVal(row, '是否人工修正'))) item.corrected += 1;
}

const operators = [...operatorMap.values()].map((operator) => ({
  ...operator,
  accuracy: operator.total ? operator.passed / operator.total : 0,
  correctionRate: operator.total ? operator.corrected / operator.total : 0,
  nickname: nickOf(operator.userId, operator.name)
})).sort((a, b) => b.total - a.total);

const recent = scopedBatches.map((batch) => {
  const total = num(propVal(batch, '總筆數'));
  const passed = num(propVal(batch, '通過筆數'));
  const abnormal = num(propVal(batch, '異常筆數'));
  return {
    time: batchTime(batch),
    batchId: propVal(batch, '批次ID') || propVal(batch, '名稱'),
    operator: propVal(batch, '操作人'),
    operatorNick: nickOf(propVal(batch, 'LINE userId'), propVal(batch, '操作人')),
    orderNo: propVal(batch, '製令單號'),
    status: propVal(batch, '狀態'),
    notifyStatus: propVal(batch, '通知狀態'),
    processingSeconds: num(propVal(batch, '處理秒數')),
    total,
    passed,
    abnormal,
    accuracy: total ? passed / total : 0
  };
}).sort((a, b) => String(b.time).localeCompare(String(a.time))).slice(0, 30);

const dailyMap = new Map();
for (const batch of scopedBatches) {
  const day = dayKey(parseTime(batchTime(batch)));
  if (!day) continue;
  if (!dailyMap.has(day)) dailyMap.set(day, { date: day, batches: 0, total: 0, passed: 0, abnormal: 0 });
  const bucket = dailyMap.get(day);
  bucket.batches += 1;
  bucket.total += num(propVal(batch, '總筆數'));
  bucket.passed += num(propVal(batch, '通過筆數'));
  bucket.abnormal += num(propVal(batch, '異常筆數'));
}
const daily = [...dailyMap.values()]
  .map((d) => ({ ...d, accuracy: d.total ? d.passed / d.total : 0 }))
  .sort((a, b) => a.date.localeCompare(b.date));

const errorMap = new Map();
for (const row of abnormalDetails) {
  for (const type of errorTypesOf(row)) {
    errorMap.set(type, (errorMap.get(type) || 0) + 1);
  }
}
const errorTypes = [...errorMap.entries()]
  .map(([name, count]) => ({ name, count }))
  .sort((a, b) => b.count - a.count);

const ocrStatusMap = new Map();
for (const row of scopedDetails) {
  const s = String(propVal(row, 'OCR狀態') || '未標記').trim() || '未標記';
  ocrStatusMap.set(s, (ocrStatusMap.get(s) || 0) + 1);
}
const ocrStatus = [...ocrStatusMap.entries()].map(([name, count]) => ({ name, count }));

const partMap = new Map();
for (const row of abnormalDetails) {
  const part = String(propVal(row, '品號') || propVal(row, '原始品號') || '').trim() || '（空品號）';
  if (!partMap.has(part)) partMap.set(part, { partNo: part, count: 0, reasons: new Set() });
  const item = partMap.get(part);
  item.count += 1;
  for (const t of errorTypesOf(row)) item.reasons.add(t);
}
const problemParts = [...partMap.values()]
  .map((p) => ({ partNo: p.partNo, count: p.count, reasons: [...p.reasons] }))
  .sort((a, b) => b.count - a.count)
  .slice(0, 10);

const notifyMap = new Map();
for (const batch of scopedBatches) {
  const s = String(propVal(batch, '通知狀態') || '未記錄').trim() || '未記錄';
  notifyMap.set(s, (notifyMap.get(s) || 0) + 1);
}
const notify = [...notifyMap.entries()].map(([name, count]) => ({ name, count }));

const failedBatches = scopedBatches.filter((b) => String(propVal(b, '狀態')) === '失敗').length;
const correctedItems = scopedDetails.filter((row) => truthy(propVal(row, '是否人工修正'))).length;
const completeItems = scopedDetails.filter((row) => String(propVal(row, 'OCR狀態')) === '辨識完成').length;
const processedBatches = scopedBatches.filter((b) => num(propVal(b, '處理秒數')) > 0);
const avgProcessing = processedBatches.length
  ? processedBatches.reduce((sum, b) => sum + num(propVal(b, '處理秒數')), 0) / processedBatches.length
  : 0;

const detailRows = scopedDetails.slice(-1000).map((row) => ({
  batchId: String(propVal(row, '批次ID') || ''),
  partNo: String(propVal(row, '品號') || propVal(row, '原始品號') || ''),
  spec: String(propVal(row, '規格') || ''),
  status: String(propVal(row, '比對結果') || ''),
  ocrStatus: String(propVal(row, 'OCR狀態') || ''),
  corrected: truthy(propVal(row, '是否人工修正')),
  errorTypes: errorTypesOf(row),
  note: String(propVal(row, '異常原因') || propVal(row, '備註') || '')
}));

const totalItems = scopedDetails.length;
const passedItems = passedDetails.length;
const abnormalItems = abnormalDetails.length;
const todayBatches = scopedBatches.filter((batch) => sameDay(parseTime(batchTime(batch)))).length;

return [{
  json: {
    ok: true,
    summary: {
      accuracy_rate: totalItems ? passedItems / totalItems : 0,
      total_items: totalItems,
      passed_items: passedItems,
      abnormal_items: abnormalItems,
      total_batches: scopedBatches.length,
      today_batches: todayBatches,
      failed_batches: failedBatches,
      corrected_items: correctedItems,
      correction_rate: totalItems ? correctedItems / totalItems : 0,
      ocr_complete_rate: totalItems ? completeItems / totalItems : 0,
      avg_processing_seconds: Math.round(avgProcessing * 10) / 10
    },
    operators,
    recent,
    daily,
    errorTypes,
    ocrStatus,
    problemParts,
    notify,
    details: detailRows
  }
}];
